using System.IO;
using System.Text.RegularExpressions;
using TestProject.Tests.TestHelpers;
using Xunit;

namespace TestProject.Tests;

/// <summary>
/// Security wiring tests for the HTTP request pipeline and DI registrations
/// in <c>Program.cs</c>.
///
/// <para>
/// <c>[Authorize]</c> on <see cref="TestProject.Controllers.FilesController"/>
/// is only effective when the ASP.NET Core authentication/authorization
/// infrastructure is actually wired into the host: the services must be
/// registered before <c>builder.Build()</c> and the two middlewares must run
/// in the request pipeline in the correct order before the endpoints are
/// mapped. Without any of these, an unauthenticated request to
/// <c>/api/files/*</c> still succeeds, so the file-management surface stays
/// open exactly as the security finding describes.
/// </para>
///
/// <para>
/// These tests assert the presence, count and relative ordering of the
/// authentication/authorization calls by parsing the source of
/// <c>Program.cs</c> directly — the same strategy used by
/// <see cref="ProgramWiringTests"/> — so the contract is locked in regardless
/// of formatting choices.
/// </para>
///
/// The required contract (the preferred fix):
/// <list type="bullet">
/// <item><c>AddAuthentication(...)</c> is registered on the services
/// collection, chained to a scheme handler (<c>.AddCookie</c> or
/// <c>.AddJwtBearer</c>).</item>
/// <item><c>AddAuthorization()</c> is registered on the services
/// collection.</item>
/// <item>Both registrations occur before <c>builder.Build()</c>.</item>
/// <item><c>UseAuthentication()</c> and <c>UseAuthorization()</c> are each
/// present exactly once in the pipeline.</item>
/// <item><c>UseAuthentication()</c> precedes <c>UseAuthorization()</c>
/// (the principal must be established before it is authorized).</item>
/// <item><c>UseAuthorization()</c> precedes <c>MapControllers()</c> (so the
/// <c>[Authorize]</c> attribute is enforced on every routed endpoint).</item>
/// <item><c>UseAuthorization()</c> precedes the SPA fallback and
/// <c>app.Run()</c>.</item>
/// </list>
/// </summary>
public class ProgramSecurityWiringTests
{
    private static readonly string ProgramSource = SourceFileLoader.LoadAdjacent("Program.cs");

    // Authentication/authorization must not be left at the framework default
    // (open). Pin each required call.

    private const string AddAuthenticationPattern = @"AddAuthentication\s*\(";
    private const string AddAuthorizationPattern = @"AddAuthorization\s*\(";
    private const string UseAuthenticationPattern = @"UseAuthentication\s*\(";
    private const string UseAuthorizationPattern = @"UseAuthorization\s*\(";

    private const string MapControllersPattern = @"MapControllers\s*\(";
    private const string FallbackIndexHtmlPattern =
        @"MapFallbackToFile\s*\(\s*""index\.html""\s*\)";
    private const string RunPattern = @"\.\s*Run\s*\(\s*\)";
    private const string BuildPattern = @"\.\s*Build\s*\(\s*\)";

    private const string CookieSchemePattern = @"\.AddCookie\s*\(";
    private const string JwtSchemePattern = @"\.AddJwtBearer\s*\(";

    /// <summary>Returns the index of the first match of <paramref name="pattern"/>,
    /// or -1 when it is absent.</summary>
    private static int IndexOf(string pattern)
    {
        var match = Regex.Match(ProgramSource, pattern);
        return match.Success ? match.Index : -1;
    }

    /// <summary>Counts how many times <paramref name="pattern"/> matches.</summary>
    private static int Count(string pattern) =>
        Regex.Matches(ProgramSource, pattern).Count;

    private static void AssertPresent(string pattern, string description)
    {
        Assert.True(IndexOf(pattern) >= 0,
            $"Expected {description} to be present in Program.cs so the " +
            "/api/files/* surface is access-controlled.");
    }

    // =====================================================================
    // Service registration: authentication
    // =====================================================================

    [Fact]
    public void Program_RegistersAuthentication_OnServicesCollection()
    {
        AssertPresent(AddAuthenticationPattern, "AddAuthentication(...)");
    }

    [Fact]
    public void Program_RegistersAuthentication_BeforeBuild()
    {
        var auth = IndexOf(AddAuthenticationPattern);
        var build = IndexOf(BuildPattern);

        Assert.True(auth >= 0, "Expected AddAuthentication(...) in Program.cs.");
        Assert.True(build >= 0, "Expected builder.Build() in Program.cs.");
        Assert.True(auth < build,
            "AddAuthentication must be registered before builder.Build().");
    }

    [Fact]
    public void Program_RegistersAuthenticationSchemeHandler()
    {
        // AddAuthentication alone (with no handler) rejects everyone — which
        // closes the surface but makes the API unusable. The preferred fix
        // wires a concrete scheme handler (cookie or JWT, per the finding) so
        // an authenticated principal can actually be established. Accept the
        // two documented examples.
        Assert.True(IndexOf(CookieSchemePattern) >= 0 || IndexOf(JwtSchemePattern) >= 0,
            "Expected AddAuthentication(...) to be chained with a scheme handler " +
            "(.AddCookie(...) or .AddJwtBearer(...)) in Program.cs.");
    }

    // =====================================================================
    // Service registration: authorization
    // =====================================================================

    [Fact]
    public void Program_RegistersAuthorization_OnServicesCollection()
    {
        AssertPresent(AddAuthorizationPattern, "AddAuthorization(...)");
    }

    [Fact]
    public void Program_RegistersAuthorization_BeforeBuild()
    {
        var authz = IndexOf(AddAuthorizationPattern);
        var build = IndexOf(BuildPattern);

        Assert.True(authz >= 0, "Expected AddAuthorization(...) in Program.cs.");
        Assert.True(build >= 0, "Expected builder.Build() in Program.cs.");
        Assert.True(authz < build,
            "AddAuthorization must be registered before builder.Build().");
    }

    // =====================================================================
    // Pipeline middleware: present exactly once
    // =====================================================================

    [Fact]
    public void Program_Pipeline_UsesAuthentication_ExactlyOnce()
    {
        Assert.Equal(1, Count(UseAuthenticationPattern));
    }

    [Fact]
    public void Program_Pipeline_UsesAuthorization_ExactlyOnce()
    {
        Assert.Equal(1, Count(UseAuthorizationPattern));
    }

    // =====================================================================
    // Pipeline middleware: present after Build (i.e. on the app pipeline)
    // =====================================================================

    [Fact]
    public void Program_Pipeline_UseAuthentication_ComesAfterBuild()
    {
        var build = IndexOf(BuildPattern);
        var auth = IndexOf(UseAuthenticationPattern);

        Assert.True(build >= 0 && auth >= 0);
        Assert.True(build < auth,
            "builder.Build() must occur before UseAuthentication() is called on the pipeline.");
    }

    [Fact]
    public void Program_Pipeline_UseAuthorization_ComesAfterBuild()
    {
        var build = IndexOf(BuildPattern);
        var authz = IndexOf(UseAuthorizationPattern);

        Assert.True(build >= 0 && authz >= 0);
        Assert.True(build < authz,
            "builder.Build() must occur before UseAuthorization() is called on the pipeline.");
    }

    // =====================================================================
    // Pipeline ordering — the security-critical part
    // =====================================================================

    [Fact]
    public void Program_Pipeline_UseAuthentication_ComesBeforeUseAuthorization()
    {
        // The authenticated principal must be established by
        // UseAuthentication BEFORE UseAuthorization consults it, otherwise
        // every request is treated as anonymous regardless of credentials.
        var auth = IndexOf(UseAuthenticationPattern);
        var authz = IndexOf(UseAuthorizationPattern);

        Assert.True(auth >= 0, "Expected UseAuthentication() in Program.cs.");
        Assert.True(authz >= 0, "Expected UseAuthorization() in Program.cs.");
        Assert.True(auth < authz,
            "UseAuthentication() must precede UseAuthorization() in the request pipeline.");
    }

    [Fact]
    public void Program_Pipeline_UseAuthorization_ComesBeforeMapControllers()
    {
        // This is the single most important ordering rule for the fix: the
        // authorization middleware MUST run before endpoint routing resolves
        // the request to a controller action, otherwise the [Authorize]
        // attribute on FilesController is never enforced and the whole
        // /api/files/* surface stays open.
        var authz = IndexOf(UseAuthorizationPattern);
        var controllers = IndexOf(MapControllersPattern);

        Assert.True(authz >= 0, "Expected UseAuthorization() in Program.cs.");
        Assert.True(controllers >= 0, "Expected MapControllers() in Program.cs.");
        Assert.True(authz < controllers,
            "UseAuthorization() must precede MapControllers() so the [Authorize] " +
            "attribute is enforced on every /api/files/* endpoint.");
    }

    [Fact]
    public void Program_Pipeline_UseAuthorization_ComesBeforeFallbackAndRun()
    {
        var authz = IndexOf(UseAuthorizationPattern);
        var fallback = IndexOf(FallbackIndexHtmlPattern);
        var run = IndexOf(RunPattern);

        Assert.True(authz >= 0, "Expected UseAuthorization() in Program.cs.");
        Assert.True(fallback >= 0, "Expected MapFallbackToFile(\"index.html\") in Program.cs.");
        Assert.True(run >= 0, "Expected app.Run() in Program.cs.");
        Assert.True(authz < fallback, "UseAuthorization() must precede MapFallbackToFile().");
        Assert.True(authz < run, "UseAuthorization() must precede app.Run().");
    }

    [Fact]
    public void Program_Pipeline_AuthMiddlewareComesBeforeAllEndpoints()
    {
        // Composite check: UseAuthentication < UseAuthorization < MapControllers
        // < MapFallbackToFile < Run, the documented end-to-end ordering.
        var auth = IndexOf(UseAuthenticationPattern);
        var authz = IndexOf(UseAuthorizationPattern);
        var controllers = IndexOf(MapControllersPattern);
        var fallback = IndexOf(FallbackIndexHtmlPattern);
        var run = IndexOf(RunPattern);

        Assert.True(auth >= 0 && authz >= 0 && controllers >= 0 &&
                    fallback >= 0 && run >= 0,
            "All expected authentication/authorization pipeline statements must be present.");

        Assert.True(auth < authz,
            "Order: UseAuthentication must precede UseAuthorization.");
        Assert.True(authz < controllers,
            "Order: UseAuthorization must precede MapControllers.");
        Assert.True(controllers < fallback,
            "Order: MapControllers must precede MapFallbackToFile.");
        Assert.True(fallback < run,
            "Order: MapFallbackToFile must precede Run.");
    }

    // =====================================================================
    // Documentation: the access-control posture must be documented in the
    // README (fix instruction: "Document the chosen posture ... in README.md
    // so the open-by-default behavior is not accidentally deployed").
    // =====================================================================

    [Fact]
    public void Readme_DocumentsAccessControlPosture()
    {
        var readme = SourceFileLoader.LoadAdjacent("README.md");

        var mentionsAccessControl =
            readme.Contains("authoriz", StringComparison.OrdinalIgnoreCase) ||
            readme.Contains("authentication", StringComparison.OrdinalIgnoreCase);

        Assert.True(mentionsAccessControl,
            "README.md must document the access-control posture for the /api/files/* " +
            "surface (e.g. that the API requires authentication/authorization) so the " +
            "open-by-default behavior is not accidentally deployed.");
    }
}

using System.Reflection;
using Microsoft.AspNetCore.Authorization;
using Microsoft.AspNetCore.Mvc;
using TestProject.Controllers;
using TestProject.Tests.TestHelpers;
using Xunit;

namespace TestProject.Tests.Controllers;

/// <summary>
/// Security tests for <see cref="FilesController"/>.
///
/// The file-management API surface (<c>/api/files/*</c>) exposes browse,
/// read, upload, download, delete, move and copy operations directly against
/// the server's file system. Before this work it accepted every request with
/// no authentication or authorization, so any reachable client could enumerate
/// and mutate files. These tests pin the access-control posture that the
/// preferred fix (ASP.NET Core authentication/authorization) must establish:
///
/// <list type="bullet">
/// <item>The whole controller surface must be protected with a class-level
/// <c>[Authorize]</c> attribute so that browse/read (non-mutating) endpoints
/// are protected just like delete/move/copy — the finding calls out the
/// <em>entire</em> surface as exposed.</item>
/// <item>That attribute must be the real
/// <see cref="Microsoft.AspNetCore.Authorization.AuthorizeAttribute"/>, not an
/// accidental look-alike from another namespace.</item>
/// <item>No action may opt back out with <c>[AllowAnonymous]</c>, which would
/// silently re-open an endpoint.</item>
/// <item>Every HTTP action method must ultimately be reachable only through an
/// <c>[Authorize]</c> (class-level counts for all of them).</item>
/// </list>
///
/// <para>
/// These assertions use reflection only. <c>[Authorize]</c> is metadata that
/// the authorization middleware enforces at request time; calling an action
/// method directly (as <see cref="FilesControllerTests"/> does) is unaffected,
/// so the existing behavioral tests remain valid once the attribute is added.
/// </para>
/// </summary>
public class FilesControllerAuthorizationTests
{
    /// <summary>
    /// The set of ASP.NET Core MVC HTTP-verb attribute types that mark a
    /// public action method on the controller. Used to enumerate the actual
    /// endpoints rather than private helpers or inherited Object methods.
    /// </summary>
    private static readonly HashSet<string> HttpVerbAttributeNames = new(StringComparer.Ordinal)
    {
        nameof(HttpGetAttribute),
        nameof(HttpPostAttribute),
        nameof(HttpPutAttribute),
        nameof(HttpPatchAttribute),
        nameof(HttpDeleteAttribute),
        nameof(HttpHeadAttribute),
        nameof(HttpOptionsAttribute),
    };

    private static IEnumerable<MethodInfo> PublicActionMethods()
    {
        return typeof(FilesController)
            .GetMethods(BindingFlags.Public | BindingFlags.Instance | BindingFlags.DeclaredOnly)
            .Where(m => !m.IsSpecialName)            // skip property accessors etc.
            .Where(IsActionMethod);
    }

    private static bool IsActionMethod(MethodInfo method)
    {
        // A method is considered an action when it carries an HTTP-verb route
        // attribute ([HttpGet], [HttpPost], ...). This deliberately excludes
        // private helpers (Execute, ExecuteAsync, NormalizeRelativePath) and
        // the constructor.
        return method.GetCustomAttributes()
            .Any(a => HttpVerbAttributeNames.Contains(a.GetType().Name)
                      && a.GetType().Namespace == "Microsoft.AspNetCore.Mvc");
    }

    // =====================================================================
    // Class-level [Authorize]
    // =====================================================================

    [Fact]
    public void FilesController_ClassIsDecoratedWithAuthorizeAttribute()
    {
        // The finding flags the WHOLE surface (browse/read/write/delete) as
        // exposed. Protecting the entire controller with a single class-level
        // [Authorize] is the cleanest, preferred way to close every endpoint
        // at once and to keep future endpoints protected by default.
        var attributes = typeof(FilesController)
            .GetCustomAttributes(typeof(AuthorizeAttribute), inherit: true);

        Assert.NotEmpty(attributes);
    }

    [Fact]
    public void FilesController_AuthorizeAttributeIsTheAspNetCoreOne()
    {
        // Guard against a look-alike [Authorize] from a different namespace
        // (e.g. a stray custom attribute) that would not be honored by the
        // ASP.NET Core authorization middleware.
        var authorize = typeof(FilesController)
            .GetCustomAttributes(typeof(AuthorizeAttribute), inherit: true)
            .Cast<AuthorizeAttribute>()
            .SingleOrDefault();

        Assert.NotNull(authorize);
        // Exactly the built-in AuthorizeAttribute — not a look-alike from another
        // namespace and not a custom subclass that the ASP.NET Core middleware
        // might not recognize. typeof(AuthorizeAttribute) resolves to the
        // Microsoft.AspNetCore.Authorization type the test project already
        // references.
        Assert.Equal(typeof(AuthorizeAttribute), authorize!.GetType());
    }

    [Fact]
    public void FilesController_HasExactlyOneClassLevelAuthorizeAttribute()
    {
        // Exactly one class-level [Authorize]. Multiple contradictory
        // attributes would be confusing/ambiguous; absence would re-open the
        // surface (covered by the presence test above).
        var count = typeof(FilesController)
            .GetCustomAttributes(typeof(AuthorizeAttribute), inherit: true)
            .Length;

        Assert.Equal(1, count);
    }

    // =====================================================================
    // No endpoint may opt back out
    // =====================================================================

    [Fact]
    public void FilesController_NoActionAllowsAnonymous()
    {
        // [AllowAnonymous] bypasses a class-level [Authorize]. If any action
        // carried it, that endpoint would be reachable by unauthenticated
        // clients — re-opening the hole this fix is meant to close.
        var offenders = PublicActionMethods()
            .Where(m => m.GetCustomAttributes(typeof(AllowAnonymousAttribute), inherit: true).Any())
            .Select(m => m.Name)
            .ToList();

        Assert.Empty(offenders);
    }

    [Fact]
    public void FilesController_AllActionsAreCoveredByAuthorize()
    {
        // Belt-and-suspenders: regardless of whether protection is applied at
        // the class or per-action level, every HTTP endpoint must ultimately
        // be reachable only through an [Authorize]. Asserts both that the
        // known endpoints exist (so the test fails if the action set changes
        // silently) and that none is left open.
        var expectedActions = new HashSet<string>(StringComparer.Ordinal)
        {
            nameof(FilesController.Browse),
            nameof(FilesController.Search),
            nameof(FilesController.Upload),
            nameof(FilesController.Download),
            nameof(FilesController.Delete),
            nameof(FilesController.Move),
            nameof(FilesController.Copy),
        };

        var actualActions = PublicActionMethods().Select(m => m.Name).ToList();
        Assert.True(expectedActions.SetEquals(actualActions),
            "Unexpected action set on FilesController: " +
            $"[{string.Join(", ", actualActions)}]. Update the expected set if the API " +
            "surface changed intentionally; every entry here must remain authorized.");

        foreach (var method in PublicActionMethods())
        {
            var authorizedOnMethod = method
                .GetCustomAttributes(typeof(AuthorizeAttribute), inherit: true).Any();
            var authorizedOnClass = typeof(FilesController)
                .GetCustomAttributes(typeof(AuthorizeAttribute), inherit: true).Any();

            Assert.True(authorizedOnMethod || authorizedOnClass,
                $"Action '{method.Name}' is not covered by any [Authorize] " +
                "(neither on the method nor on the controller class).");
        }
    }

    // =====================================================================
    // Mutating endpoints specifically (delete/move/copy/upload) must be gated.
    // The finding calls these out by name; pin them explicitly so a future
    // "only authorize mutating actions" refactor cannot leave them open.
    // =====================================================================

    [Theory]
    [InlineData(nameof(FilesController.Upload))]
    [InlineData(nameof(FilesController.Delete))]
    [InlineData(nameof(FilesController.Move))]
    [InlineData(nameof(FilesController.Copy))]
    public void FilesController_MutatingActionIsAuthorized(string actionName)
    {
        var method = PublicActionMethods().Single(m => m.Name == actionName);

        var authorizedOnMethod = method
            .GetCustomAttributes(typeof(AuthorizeAttribute), inherit: true).Any();
        var authorizedOnClass = typeof(FilesController)
            .GetCustomAttributes(typeof(AuthorizeAttribute), inherit: true).Any();

        Assert.True(authorizedOnMethod || authorizedOnClass,
            $"Mutating action '{actionName}' must be protected by [Authorize].");
    }

    // =====================================================================
    // Read endpoints (browse/search/download) must ALSO be gated — the
    // finding flags browse/read as exposed, not just writes.
    // =====================================================================

    [Theory]
    [InlineData(nameof(FilesController.Browse))]
    [InlineData(nameof(FilesController.Search))]
    [InlineData(nameof(FilesController.Download))]
    public void FilesController_ReadActionIsAuthorized(string actionName)
    {
        var method = PublicActionMethods().Single(m => m.Name == actionName);

        var authorizedOnMethod = method
            .GetCustomAttributes(typeof(AuthorizeAttribute), inherit: true).Any();
        var authorizedOnClass = typeof(FilesController)
            .GetCustomAttributes(typeof(AuthorizeAttribute), inherit: true).Any();

        Assert.True(authorizedOnMethod || authorizedOnClass,
            $"Read action '{actionName}' must be protected by [Authorize]; the finding " +
            "flags browse/read (not just writes) as exposed.");
    }

    // =====================================================================
    // The access-control posture must be documented in the controller's XML
    // doc comment (fix instruction: "Document the chosen posture in the
    // controller XML doc comment"). Asserts the documentation lives in a
    // `///` comment, not merely in the [Authorize] attribute text.
    // =====================================================================

    [Fact]
    public void FilesController_XmlDocDocumentsAccessControlPosture()
    {
        var source = SourceFileLoader.LoadAdjacent("Controllers", "FilesController.cs");

        var docLines = source.Split('\n')
            .Select(l => l.TrimStart())
            .Where(l => l.StartsWith("///"))
            .ToList();

        Assert.NotEmpty(docLines);

        // IMPORTANT: exclude doc lines that document the file-system exception
        // types caught by Execute/ExecuteAsync. The existing comment mentions
        // `UnauthorizedAccessException` (an OS-level access-denied exception
        // translated into a 400), whose substring "authoriz" would otherwise
        // satisfy this check for the wrong reason and hide a missing security
        // note. A genuine access-control statement does not reference exception
        // types, so filtering them out keeps the assertion meaningful.
        var postureLines = docLines
            .Where(l => !l.Contains("Exception", StringComparison.OrdinalIgnoreCase))
            .ToList();

        var mentionsAccessControl = postureLines.Any(line =>
            line.Contains("authenticat", StringComparison.OrdinalIgnoreCase) ||
            line.Contains("authoriz", StringComparison.OrdinalIgnoreCase) ||
            line.Contains("access control", StringComparison.OrdinalIgnoreCase) ||
            line.Contains("access-control", StringComparison.OrdinalIgnoreCase));

        Assert.True(mentionsAccessControl,
            "The FilesController XML doc comment must document the access-control " +
            "posture (e.g. that the API requires an authenticated/authorized caller). " +
            "Note: references to UnauthorizedAccessException do NOT count, as that is an " +
            "exception type, not an access-control statement.");
    }
}

